SELECT * FROM RDITAG_TB 
WHERE 1=1

	AND (TAG_NM LIKE '%'||LOWER(#{searchwd})||'%' OR TAG_NM LIKE '%'||UPPER(#{searchwd})||'%' OR TAG_NM LIKE '%'||#{searchwd}||'%')


	AND TAG_ADIT_DC LIKE '%'||#{search_desc}||'%'


	AND PROCS_ID = #{procs_id}


	AND FCLT_ID = #{fclt_id}


	AND FCLT_DTL_ID = #{fclt_dtl_id}

ORDER BY TAGSN

SELECT TAGSN, TAG_NM, TAG_ADIT_DC, PROCS_ID , (SELECT PROCS_NM FROM RDIPROCSINFO_TB P WHERE P.PROCS_ID = T.PROCS_ID) AS PROCS_NM, FCLT_ID , (SELECT CD_NM FROM RDICMMNCD_TB WHERE CD_SE='CD101' AND CD_ID = T.FCLT_ID) AS FCLT_NM, FCLT_DTL_ID , ( SELECT CD_NM FROM RDICMMNCD_TB WHERE CD_SE = T.FCLT_ID AND CD_ID = T.FCLT_DTL_ID ) AS FCLT_DETAIL_NM FROM RDITAG_TB T WHERE 1=1
AND (TAG_NM LIKE '%' || UPPER(#{search_wd}) || '%' OR TAG_NM LIKE '%' || LOWER(#{search_wd}) || '%')
AND PROCS_ID IN (
#{item}
)
AND PROCS_ID IS NULL
AND FCLT_ID IN (
#{item}
)
AND FCLT_ID IS NULL
ORDER BY PROCS_ID, TAGSN
